mapper.select:
SELECT * FROM legal_category
AND name LIKE CONCAT('%',#{name},'%') AND status=#{status}
ORDER BY id DESC

SELECT l.*, GROUP_CONCAT(DISTINCT c.name ORDER BY c.id) category_names, GROUP_CONCAT(DISTINCT c.id ORDER BY c.id) category_ids FROM lawyer l LEFT JOIN lawyer_category lc ON l.id=lc.lawyer_id AND lc.status=1 LEFT JOIN legal_category c ON lc.category_id=c.id
AND l.name LIKE CONCAT('%',#{name},'%') AND EXISTS(SELECT 1 FROM lawyer_category x WHERE x.lawyer_id=l.id AND x.category_id=#{categoryId} AND x.status=1) AND l.status=#{status}
GROUP BY l.id ORDER BY l.id DESC

SELECT s.*,l.name lawyer_name FROM lawyer_schedule s JOIN lawyer l ON s.lawyer_id=l.id

    AND s.lawyer_id=#{lawyerId}
    AND s.end_time >= #{fromTime}

ORDER BY s.start_time

SELECT COUNT(*) FROM lawyer_schedule WHERE lawyer_id=#{lawyerId} AND status!=2
AND start_time < #{endTime} AND end_time > #{startTime}
AND id!=#{excludeId}

SELECT COUNT(*) FROM consult_appointment
WHERE lawyer_id=#{lawyerId} AND status IN(0,1,3)
  AND start_time < #{endTime} AND end_time > #{startTime}
AND id!=#{excludeId}

SELECT a.*,l.name lawyer_name,l.phone old_phone,l.introduction old_introduction, GROUP_CONCAT(c.name ORDER BY c.id) old_category_names FROM lawyer_update_apply a JOIN lawyer l ON a.lawyer_id=l.id LEFT JOIN lawyer_category lc ON l.id=lc.lawyer_id LEFT JOIN legal_category c ON lc.category_id=c.id
AND a.lawyer_id=#{refId} AND a.status=#{status}
GROUP BY a.id ORDER BY a.create_time DESC
